function AbsoluteDifference(a: int, b: int): int
{
  if a > b then a - b else b - a
}

predicate threeSumClosestPost(nums: seq<int>, target: int, result: int)
{
  |nums| >= 3
  &&
  (exists i,j,k :: 0 <= i < j < k < |nums| &&
                 nums[i] + nums[j] + nums[k] == result)
  &&
  (forall i,j,k :: 0 <= i < j < k < |nums| ==>
       AbsoluteDifference(nums[i] + nums[j] + nums[k], target)
         >= AbsoluteDifference(result, target))
}

// A triple sum is achievable in a sequence
predicate tripleAchievable(s: seq<int>, v: int)
{
  exists i, j, k :: 0 <= i < j < k < |s| && s[i] + s[j] + s[k] == v
}

// Lemma: if two sequences have the same multiset, any triple sum in one is achievable in the other
lemma multisetTripleEquiv(a: seq<int>, b: seq<int>, v: int)
  requires multiset(a) == multiset(b)
  requires tripleAchievable(a, v)
  ensures tripleAchievable(b, v)
{
  var i, j, k :| 0 <= i < j < k < |a| && a[i] + a[j] + a[k] == v;
  // a[i], a[j], a[k] are in multiset(a) = multiset(b)
  // So they appear in b as well
  assert a[i] in multiset(a);
  assert a[j] in multiset(a);
  assert a[k] in multiset(a);

  // We need to find distinct indices in b
  // Since multisets are equal, |a| == |b|
  assert |a| == |b|;

  // Use the fact that a[i], a[j], a[k] are at distinct positions in a
  // and their combined multiplicity is preserved in b
  multisetDistinctIndices(a, b, i, j, k);
}

// Helper lemma: given distinct indices in a, find distinct indices in b with same values
lemma multisetDistinctIndices(a: seq<int>, b: seq<int>, i: int, j: int, k: int)
  requires multiset(a) == multiset(b)
  requires 0 <= i < j < k < |a|
  ensures exists i', j', k' :: 0 <= i' < j' < k' < |b| && b[i'] + b[j'] + b[k'] == a[i] + a[j] + a[k]
{
  assert |a| == |b|;
  // We know a[i] in multiset(a) = multiset(b), so a[i] in multiset(b)
  // This means there's some index in b with that value
  var vi, vj, vk := a[i], a[j], a[k];

  // Build a sub-multiset from the three elements
  // We need to pick 3 elements from b carefully
  // Since multiset(a) == multiset(b) and we can pick {a[i], a[j], a[k]} from a,
  // those elements (with multiplicity) exist in b too.

  // a[i] in multiset(b)
  assert vi in multiset(b);
  var i' :| 0 <= i' < |b| && b[i'] == vi;

  // After "removing" b[i'], the remaining still contains vj and vk
  // multiset(a) - multiset{vi} still contains vj (since j != i, a[j] is still there)
  // And multiset(b) - multiset{b[i']} = multiset(a) - multiset{vi}

  // Let's use a different approach: construct the sequence without index i'
  var b' := b[..i'] + b[i'+1..];
  assert multiset(b') == multiset(b) - multiset{vi};

  // From a, removing a[i], the remaining has a[j] and a[k]
  var a' := a[..i] + a[i+1..];
  assert multiset(a') == multiset(a) - multiset{vi};
  assert multiset(a') == multiset(b');

  // a[j] is in a' at some position
  assert vj in multiset(a');
  assert vj in multiset(b');
  var j'' :| 0 <= j'' < |b'| && b'[j''] == vj;

  // Now remove that too
  var b'' := b'[..j''] + b'[j''+1..];
  // Also from a' we can find a[k]
  // In a', a[k] was at position k-1 (if k > i) or k (if k < i, but k > i since i < j < k)
  // So a[k] = a'[k-1]
  var a'' := a'[..j''] + a'[j''+1..]; // not quite right, let's just use multisets
  assert multiset(b'') == multiset(b') - multiset{vj};
  assert multiset(a') - multiset{vj} == multiset(b') - multiset{vj};

  // a[k] is in multiset(a) - multiset{vi} - multiset{vj}
  // Because a[i], a[j], a[k] are at distinct indices in a
  multisetSubtractThree(a, i, j, k);
  assert vk in multiset(a) - multiset{vi} - multiset{vj};
  assert vk in multiset(b'');
  var k'' :| 0 <= k'' < |b''| && b''[k''] == vk;

  // Now convert j'', k'' back to indices in b
  var j' := if j'' < i' then j'' else j'' + 1;
  assert 0 <= j' < |b| && j' != i' && b[j'] == vj;

  // For k'': first map to b' index, then to b index
  var kInB' := if k'' < j'' then k'' else k'' + 1;
  var k' := if kInB' < i' then kInB' else kInB' + 1;
  assert 0 <= k' < |b| && b[k'] == vk;
  assert k' != i';
  assert k' != j';

  // Now we have i', j', k' all distinct in b with b[i']+b[j']+b[k'] == vi+vj+vk
  // We just need to sort them to get i' < j' < k'
  var a1, b1, c1 := sortThree(i', j', k');
  assert b[a1] + b[b1] + b[c1] == vi + vj + vk;
}

// Lemma: three distinct indices in a sequence contribute distinct elements to the multiset
lemma multisetSubtractThree(a: seq<int>, i: int, j: int, k: int)
  requires 0 <= i < j < k < |a|
  ensures a[k] in multiset(a) - multiset{a[i]} - multiset{a[j]}
{
  // multiset(a)[a[k]] >= 1 since k is a valid index
  // We need to show that after removing one copy of a[i] and one copy of a[j],
  // there's still at least one copy of a[k]

  // Count occurrences of a[k] in multiset(a)
  // It's at least 1 (from index k)
  // If a[k] == a[i] and a[k] == a[j], then multiset(a)[a[k]] >= 3 (indices i, j, k all have value a[k])
  // If a[k] == a[i] but a[k] != a[j], then multiset(a)[a[k]] >= 2 (indices i, k)
  // etc.

  // The key insight: indices i, j, k are distinct, so they each contribute 1 to the multiset count
  assert a[i] in multiset(a);
  assert a[j] in multiset(a);
  assert a[k] in multiset(a);

  // Count of a[k] in multiset(a) is at least the number of indices in {i,j,k} that have value a[k]
  var count := multiset(a)[a[k]];

  // At least index k contributes, so count >= 1
  // How many do we subtract? At most 2 (if a[i]==a[k] and a[j]==a[k])
  // But if both a[i]==a[k] and a[j]==a[k], then count >= 3

  if a[i] == a[k] && a[j] == a[k] {
    // All three have same value, count >= 3
    threeDistinctIndicesSameValue(a, i, j, k);
    assert count >= 3;
  } else if a[i] == a[k] {
    // i and k have same value, count >= 2; we subtract 1 for a[i], 0 for a[j]
    twoDistinctIndicesSameValue(a, i, k);
    assert count >= 2;
  } else if a[j] == a[k] {
    twoDistinctIndicesSameValue(a, j, k);
    assert count >= 2;
  } else {
    // a[k] != a[i] and a[k] != a[j], so we subtract 0
    assert count >= 1;
  }
}

lemma threeDistinctIndicesSameValue(a: seq<int>, i: int, j: int, k: int)
  requires 0 <= i < j < k < |a|
  requires a[i] == a[j] == a[k]
  ensures multiset(a)[a[k]] >= 3
{
  // Three distinct indices with the same value means multiplicity >= 3
  assert a[i..i+1] == [a[i]];
  assert a[j..j+1] == [a[j]];
  assert a[k..k+1] == [a[k]];
}

lemma twoDistinctIndicesSameValue(a: seq<int>, i: int, j: int)
  requires 0 <= i < j < |a|
  requires a[i] == a[j]
  ensures multiset(a)[a[j]] >= 2
{
  assert a[i..i+1] == [a[i]];
  assert a[j..j+1] == [a[j]];
}

// Sort three distinct integers
function sortThree(a: int, b: int, c: int): (int, int, int)
  requires a != b && b != c && a != c
  ensures var (x,y,z) := sortThree(a, b, c); x < y < z && {x,y,z} == {a,b,c}
{
  if a < b && a < c then
    if b < c then (a, b, c) else (a, c, b)
  else if b < a && b < c then
    if a < c then (b, a, c) else (b, c, a)
  else // c is smallest
    if a < b then (c, a, b) else (c, b, a)
}

method threeSumClosest(nums: seq<int>, target: int) returns (result: int)
  requires |nums| >= 3
  ensures  threeSumClosestPost(nums, target, result)
{
    var n := |nums|;
    if n < 3 { return 0; }

    var arr := new int[n];
    var i := 0;
    while i < n
        invariant 0 <= i <= n
        invariant arr.Length == n
        invariant forall idx :: 0 <= idx < i ==> arr[idx] == nums[idx]
    {
        arr[i] := nums[i];
        i := i + 1;
    }

    assert arr[..] == nums;
    ghost var origArr := arr[..];
    assert multiset(origArr) == multiset(nums);

    // Sort array (selection sort)
    i := 0;
    while i < n
        invariant 0 <= i <= n
        invariant arr.Length == n
        invariant multiset(arr[..]) == multiset(nums)
        invariant forall a, b :: 0 <= a < i && i <= b < n ==> arr[a] <= arr[b]
        invariant forall a, b :: 0 <= a < b < i ==> arr[a] <= arr[b]
    {
        var j := i + 1;
        while j < n
            invariant i + 1 <= j <= n
            invariant arr.Length == n
            invariant multiset(arr[..]) == multiset(nums)
            invariant forall a, b :: 0 <= a < i && i <= b < n ==> arr[a] <= arr[b]
            invariant forall a, b :: 0 <= a < b < i ==> arr[a] <= arr[b]
            invariant forall b :: i + 1 <= b < j ==> arr[i] <= arr[b]
        {
            if arr[j] < arr[i] {
                ghost var oldArr := arr[..];
                var temp := arr[i];
                arr[i] := arr[j];
