function AbsoluteDifference(a: int, b: int): int
{
  if a > b then a - b else b - a
}

predicate threeSumClosestPost(nums: seq<int>, target: int, result: int)
{
  |nums| >= 3
  &&
  (exists i,j,k :: 0 <= i < j < k < |nums| &&
                 nums[i] + nums[j] + nums[k] == result)
  &&
  (forall i,j,k :: 0 <= i < j < k < |nums| ==>
       AbsoluteDifference(nums[i] + nums[j] + nums[k], target)
         >= AbsoluteDifference(result, target))
}

// Predicate: v is achievable as a triple sum from sequence s
ghost predicate tripleAchievableOrdered(s: seq<int>, v: int)
{
  exists i, j, k :: 0 <= i < j < k < |s| && s[i] + s[j] + s[k] == v
}

// Lemma: swapping two elements preserves the multiset
lemma swapPreservesMultiset(s: seq<int>, i: int, j: int)
  requires 0 <= i < |s|
  requires 0 <= j < |s|
  ensures multiset(s[i := s[j]][j := s[i]]) == multiset(s)
{
  var s' := s[i := s[j]][j := s[i]];
  if i == j {
    assert s' == s;
  } else {
    assert |s'| == |s|;
    // Every element at index != i and != j is unchanged
    // At index i: s'[i] = s[j], at index j: s'[j] = s[i]
    // This is a swap, which preserves the multiset
  }
}

// Core lemma: if multiset(a) == multiset(b), then any triple sum achievable in a is achievable in b
// We prove this by showing we can find 3 distinct indices in b with the same values
lemma {:induction false} multisetTripleTransfer(a: seq<int>, b: seq<int>, v: int)
  requires multiset(a) == multiset(b)
  requires tripleAchievableOrdered(a, v)
  ensures tripleAchievableOrdered(b, v)
{
  var i, j, k :| 0 <= i < j < k < |a| && a[i] + a[j] + a[k] == v;
  assert |a| == |b|;

  var vi, vj, vk := a[i], a[j], a[k];

  // vi is in multiset(b)
  assert vi in multiset(a);
  assert vi in multiset(b);

  // Find first index in b with value vi
  var i' :| 0 <= i' < |b| && b[i'] == vi;

  // After removing vi from both multisets, vj is still present
  // Because i != j, a[j] contributes independently to the multiset
  ghost var msA := multiset(a);
  ghost var msB := multiset(b);

  // Show vj in msA - multiset{vi}:
  // If vi == vj, then msA[vi] >= 2 (indices i and j both have this value)
  // Otherwise, removing vi doesn't affect count of vj
  if vi == vj {
    assert a[i] == a[j];
    indexCountLemma2(a, i, j);
    assert msA[vi] >= 2;
    assert (msA - multiset{vi})[vj] >= 1;
  } else {
    assert (msA - multiset{vi})[vj] == msA[vj];
    assert a[j] in msA;
    assert msA[vj] >= 1;
  }
  assert vj in msA - multiset{vi};
  assert msA - multiset{vi} == msB - multiset{vi};
  assert vj in msB - multiset{vi};

  // So there's an index j' != i' in b with value vj
  // msB - multiset{b[i']} represents the multiset of b with one copy of vi removed
  // vj is in this multiset, so we can find j' in b, j' != i', b[j'] == vj
  // Actually, let's construct b without i' and find vj there
  ghost var b1 := b[..i'] + b[i'+1..];
  assert multiset(b1) == multiset(b) - multiset{b[i']};
  assert multiset(b1) == msB - multiset{vi};
  assert vj in multiset(b1);
  var j1 :| 0 <= j1 < |b1| && b1[j1] == vj;
  var j' := if j1 < i' then j1 else j1 + 1;
  assert 0 <= j' < |b| && j' != i' && b[j'] == vj;

  // Now show vk in msA - multiset{vi} - multiset{vj}
  // Three distinct indices i, j, k in a all have their values in the multiset
  // After removing one vi and one vj, vk is still there
  indexCountLemma3(a, i, j, k);
  assert vk in msA - multiset{vi} - multiset{vj};
  assert msA - multiset{vi} - multiset{vj} == msB - multiset{vi} - multiset{vj};
  assert vk in msB - multiset{vi} - multiset{vj};

  // Find k' in b, distinct from i' and j'
  ghost var b2 := b1[..j1] + b1[j1+1..];
  assert multiset(b2) == multiset(b1) - multiset{b1[j1]};
  assert multiset(b2) == msB - multiset{vi} - multiset{vj};
  assert vk in multiset(b2);
  var k1 :| 0 <= k1 < |b2| && b2[k1] == vk;

  // Map k1 back to index in b1
  var kInB1 := if k1 < j1 then k1 else k1 + 1;
  // Map kInB1 to index in b
  var k' := if kInB1 < i' then kInB1 else kInB1 + 1;
  assert 0 <= k' < |b| && b[k'] == vk;

  // Show k' is distinct from i' and j'
  assert k' != i';
  // Need to show k' != j'
  // kInB1 is an index in b1, and kInB1 != j1 (since k1 is an index in b2 = b1 without j1)
  assert kInB1 != j1;
  // When we map both j1 and kInB1 to b indices:
  // j' = if j1 < i' then j1 else j1 + 1
  // k' = if kInB1 < i' then kInB1 else kInB1 + 1
  // Since kInB1 != j1, we need to show the mappings don't collide
  if kInB1 == j1 {
    assert false; // contradiction
  }
  if k' == j' {
    // Both mapped from different b1 indices to same b index - impossible
    // because the mapping from b1 indices to b indices (skip i') is injective
    if kInB1 < i' && j1 < i' {
      assert k' == kInB1 && j' == j1;
      assert kInB1 == j1;
      assert false;
    } else if kInB1 >= i' && j1 >= i' {
      assert k' == kInB1 + 1 && j' == j1 + 1;
      assert kInB1 == j1;
      assert false;
    } else if kInB1 < i' && j1 >= i' {
      assert k' == kInB1 && j' == j1 + 1;
      assert kInB1 == j1 + 1;
      // kInB1 < i' and j1 >= i', so j1 + 1 > i' > kInB1...
      // Actually kInB1 < i' <= j1, so kInB1 < j1, so kInB1 != j1+1 unless...
      // kInB1 = j1 + 1 would need kInB1 > j1, but kInB1 < i' <= j1. Contradiction.
      assert kInB1 < j1;
      assert false;
    } else {
      assert kInB1 >= i' && j1 < i';
      assert k' == kInB1 + 1 && j' == j1;
      assert kInB1 + 1 == j1;
      assert j1 < i' <= kInB1;
      assert j1 <= kInB1;
      assert kInB1 + 1 == j1;
      assert false;
    }
  }
  assert k' != j';

  // Now sort i', j', k' to get ordered indices
  // We have three distinct indices i', j', k' in [0, |b|) with b values vi, vj, vk
  // and vi + vj + vk == v
  assert b[i'] + b[j'] + b[k'] == v;

  // Produce ordered triple
  if i' < j' {
    if j' < k' {
      assert 0 <= i' < j' < k' < |b| && b[i'] + b[j'] + b[k'] == v;
    } else if i' < k' {
      assert 0 <= i' < k' < j' < |b| && b[i'] + b[k'] + b[j'] == v;
    } else {
      assert 0 <= k' < i' < j' < |b| && b[k'] + b[i'] + b[j'] == v;
    }
  } else {
    if i' < k' {
      assert 0 <= j' < i' < k' < |b| && b[j'] + b[i'] + b[k'] == v;
    } else if j' < k' {
      assert 0 <= j' < k' < i' < |b| && b[j'] + b[k'] + b[i'] == v;
    } else {
      assert 0 <= k' < j' < i' < |b| && b[k'] + b[j'] + b[i'] == v;
    }
  }
}

// Helper: two distinct indices with the same value means multiplicity >= 2
lemma indexCountLemma2(s: seq<int>, i: int, j: int)
  requires 0 <= i < |s|
  requires 0 <= j < |s|
  requires i != j
  requires s[i] == s[j]
  ensures multiset(s)[s[i]] >= 2
{
  if i < j {
    indexCountHelper(s, s[i], i, j);
  } else {
    indexCountHelper(s, s[i], j, i);
  }
}

// Helper: three distinct indices - after removing values at first two, third value remains
lemma indexCountLemma3(s: seq<int>, i: int, j: int, k: int)
  requires 0 <= i < j < k < |s|
  ensures s[k] in multiset(s) - multiset{s[i]} - multiset{s[j]}
{
  var v := s[k];
  var ms := multiset(s);

  // Count how many of {i, j, k} have value v
  // We remove at most: (1 if s[i]==v) + (1 if s[j]==v) copies
  // We need: ms[v] - (1 if s[i]==v) - (1 if s[j]==v) >= 1

  // Count distinct indices in s that have value v
  // At minimum, index k has value v

  if s[i] == v && s[j] == v {
    // All three indices have value v
    // ms[v] >= 3
    indexCountHelper3(s, v, i, j, k);
    assert ms[v] >= 3;
    assert (ms - multiset{s[i]} - multiset{s[j]})[v] >= 1;
  } else if s[i] == v {
    // i and k have value v, j doesn't
    indexCountHelper(s, v, i, k);
    assert ms[v] >= 2;
    assert (ms - multiset{s[i]} - multiset{s[j]})[v] == ms[v] - 1;
    assert (ms - multiset{s[i]} - multiset{s[j]})[v] >= 1;
  } else if s[j] == v {
    indexCountHelper(s, v, j, k);
    assert ms[v] >= 2;
    assert (ms - multiset{s[i]} - multiset{s[j]})[v] == ms[v] - 1;
    assert (ms - multiset{s[i]} - multiset{s[j]})[v] >= 1;
  } else {
    // Neither s[i] nor s[j] equals v
    assert ms[v] >= 1;
    assert (ms - multiset{s[i]} - multiset{s[j]})[v] == ms[v];
    assert (ms - multiset{s[i]} - multiset{s[j]})[v] >= 1;
  }
}

lemma indexCountHelper(s: seq<int>, v: int, i: int, j: int)
  requires 0 <= i < j < |s|
  requires s[i] == v && s[j] == v
  ensures multiset(s)[v] >= 2
{
  // s = s[..i] + [s[i]] + s[i+1..j] + [s[j]] + s[j+1..]
  assert s == s[..i] + [s[i]] + s[i+1..j] + [s[j]] + s[j+1..];
  assert multiset(s) == multiset(s[..i]) + multiset{s[i]} + multiset(s[i+1..j]) + multiset{s[j]} + multiset(s[j+1..]);
}

lemma indexCountHelper3(s: seq<int>, v: int, i: int, j: int, k: int)
  requires 0 <= i < j < k < |s|
  requires s[i] == v && s[j] == v && s[k] == v
  ensures multiset(s)[v] >= 3
{
  assert s == s[..i] + [s[i]] + s[i+1..j] + [s[j]] + s[j+1..k] + [s[k]] + s[k+1..];
  assert multiset(s) == multiset(s[..i]) + multiset{s[i]} + multiset(s[i+1..j]) + multiset{s[j]} + multiset(s[j+1..k]) + multiset{s[k]} + multiset(s[k+1..]);
}

// Lemma: AbsoluteDifference is always non-negative
lemma absDiffNonNeg(a: int, b: int)
  ensures AbsoluteDifference(a, b) >= 0
