method threeSumClosest(nums: seq<int>, target: int) returns (result: int)
  requires |nums| >= 3
  ensures  threeSumClosestPost(nums, target, result)
{
    var n := |nums|;
    if n < 3 { return 0; }

    var arr := new int[n];
    var i := 0;
    while i < n
        invariant 0 <= i <= n
        invariant arr.Length == n
        invariant forall idx :: 0 <= idx < i ==> arr[idx] == nums[idx]
    {
        arr[i] := nums[i];
        i := i + 1;
    }

    assert arr[..] == nums;

    // Sort array (selection sort)
    i := 0;
    while i < n
        invariant 0 <= i <= n
        invariant arr.Length == n
        invariant multiset(arr[..]) == multiset(nums)
        invariant forall a, b :: 0 <= a < i && i <= b < n ==> arr[a] <= arr[b]
        invariant forall a, b :: 0 <= a < b < i ==> arr[a] <= arr[b]
    {
        var j := i + 1;
        while j < n
            invariant i + 1 <= j <= n
            invariant arr.Length == n
            invariant multiset(arr[..]) == multiset(nums)
            invariant forall a, b :: 0 <= a < i && i <= b < n ==> arr[a] <= arr[b]
            invariant forall a, b :: 0 <= a < b < i ==> arr[a] <= arr[b]
            invariant forall b :: i + 1 <= b < j ==> arr[i] <= arr[b]
        {
            if arr[j] < arr[i] {
                ghost var oldArr := arr[..];
                var temp := arr[i];
                arr[i] := arr[j];
                arr[j] := temp;
                // Prove multiset preservation
                assert arr[..] == oldArr[i := oldArr[j]][j := oldArr[i]];
                swapPreservesMultiset(oldArr, i, j);
                assert multiset(arr[..]) == multiset(oldArr);
            }
            j := j + 1;
        }
        i := i + 1;
    }

    // arr is now sorted and a permutation of nums
    assert multiset(arr[..]) == multiset(nums);
    assert forall a, b :: 0 <= a < b < n ==> arr[a] <= arr[b];

    var closest := arr[0] + arr[1] + arr[2];
    ghost var ci, cj, ck := 0, 1, 2;

    i := 0;
    while i < n - 2
        invariant 0 <= i <= n - 2
        invariant arr.Length == n
        invariant multiset(arr[..]) == multiset(nums)
        invariant forall a, b :: 0 <= a < b < n ==> arr[a] <= arr[b]
        invariant 0 <= ci < cj < ck < n
        invariant closest == arr[ci] + arr[cj] + arr[ck]
        invariant forall a, b, c :: 0 <= a < b < c < n && a < i ==>
            AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
    {
        var left := i + 1;
        var right := n - 1;

        while left < right
            invariant i + 1 <= left
            invariant left - 1 <= right < n
            invariant arr.Length == n
            invariant multiset(arr[..]) == multiset(nums)
            invariant forall a, b :: 0 <= a < b < n ==> arr[a] <= arr[b]
            invariant 0 <= ci < cj < ck < n
            invariant closest == arr[ci] + arr[cj] + arr[ck]
            invariant forall a, b, c :: 0 <= a < b < c < n && a < i ==>
                AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
            // Two-pointer invariant: all "skipped" triples are no better than closest
            invariant forall b, c :: i < b < c < n && (b < left || c > right) ==>
                AbsoluteDifference(arr[i] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
        {
            var curSum := arr[i] + arr[left] + arr[right];

            if curSum == target {
                closest := curSum;
                ci := i;
                cj := left;
                ck := right;

                assert tripleAchievableOrdered(arr[..], closest);
                multisetTripleTransfer(arr[..], nums, closest);

                result := curSum;
                assert AbsoluteDifference(result, target) == 0;
                return curSum;
            }

            var diffCur := if target > curSum then target - curSum else curSum - target;
            var diffClosest := if target > closest then target - closest else closest - target;

            if diffCur < diffClosest {
                closest := curSum;
                ci := i;
                cj := left;
                ck := right;
            }

            if curSum < target {
                // curSum < target. For any c <= right, arr[i] + arr[left] + arr[c] <= curSum < target
                // (because arr[c] <= arr[right] since arr is sorted)
                // So those triples have diff = target - sum >= target - curSum = diffCur >= diffClosest (after update)
                assert forall c :: i < left < c <= right ==>
                    arr[i] + arr[left] + arr[c] <= arr[i] + arr[left] + arr[right];

                left := left + 1;
            } else {
                // curSum > target (since curSum != target). For any b >= left, arr[i] + arr[b] + arr[right] >= curSum > target
                // So diff = sum - target >= curSum - target = diffCur >= diffClosest (after update)
                assert forall b :: left <= b < right ==>
                    arr[i] + arr[b] + arr[right] >= arr[i] + arr[left] + arr[right];

                right := right - 1;
            }
        }
        i := i + 1;
    }

    // Prove that all triples have been considered
    // When we exit outer loop, i == n-2, so all first-element indices 0..n-3 have been processed
    assert i == n - 2;

    // Prove achievability
    assert tripleAchievableOrdered(arr[..], closest);
    multisetTripleTransfer(arr[..], nums, closest);

    // Prove optimality
    // From the invariant: forall a, b, c :: 0 <= a < b < c < n && a < n-2 ==> ...
    // Since for any valid triple, a < n-2 (because a < b < c and c <= n-1 means a <= n-3 = n-2-1 < n-2)

    result := closest;
}

