// Key lemma for the two-pointer technique:
// In a sorted array, if arr[i] + arr[left] + arr[right] < target,
// then for any c <= right, arr[i] + arr[left] + arr[c] <= arr[i] + arr[left] + arr[right] < target
// so all those have diff >= target - (arr[i] + arr[left] + arr[right]) = current diff
// But we also need: for c < left (already skipped), we've already established optimality
lemma twoPointerLeftStep(arr: seq<int>, i: int, left: int, right: int, closest: int, target: int)
  requires 0 <= i < left < right < |arr|
  requires forall a, b :: 0 <= a < b < |arr| ==> arr[a] <= arr[b]
  requires arr[i] + arr[left] + arr[right] < target
  requires AbsoluteDifference(arr[i] + arr[left] + arr[right], target) >= AbsoluteDifference(closest, target)
  ensures forall c :: left < c <= right ==>
    AbsoluteDifference(arr[i] + arr[left] + arr[c], target) >= AbsoluteDifference(closest, target)
{
  forall c | left < c <= right
    ensures AbsoluteDifference(arr[i] + arr[left] + arr[c], target) >= AbsoluteDifference(closest, target)
  {
    // arr[c] <= arr[right] since c <= right and array is sorted
    assert arr[c] <= arr[right];
    var sum_c := arr[i] + arr[left] + arr[c];
    var sum_r := arr[i] + arr[left] + arr[right];
    assert sum_c <= sum_r;
    assert sum_r < target;
    assert sum_c < target;
    // AbsoluteDifference(sum_c, target) = target - sum_c >= target - sum_r = AbsoluteDifference(sum_r, target)
    assert AbsoluteDifference(sum_c, target) == target - sum_c;
    assert AbsoluteDifference(sum_r, target) == target - sum_r;
    assert AbsoluteDifference(sum_c, target) >= AbsoluteDifference(sum_r, target);
  }
}

lemma twoPointerRightStep(arr: seq<int>, i: int, left: int, right: int, closest: int, target: int)
  requires 0 <= i < left < right < |arr|
  requires forall a, b :: 0 <= a < b < |arr| ==> arr[a] <= arr[b]
  requires arr[i] + arr[left] + arr[right] > target
  requires AbsoluteDifference(arr[i] + arr[left] + arr[right], target) >= AbsoluteDifference(closest, target)
  ensures forall b :: left <= b < right ==>
    AbsoluteDifference(arr[i] + arr[b] + arr[right], target) >= AbsoluteDifference(closest, target)
{
  forall b | left <= b < right
    ensures AbsoluteDifference(arr[i] + arr[b] + arr[right], target) >= AbsoluteDifference(closest, target)
  {
    assert arr[b] >= arr[left];
    var sum_b := arr[i] + arr[b] + arr[right];
    var sum_l := arr[i] + arr[left] + arr[right];
    assert sum_b >= sum_l;
    assert sum_l > target;
    assert sum_b > target;
    assert AbsoluteDifference(sum_b, target) == sum_b - target;
    assert AbsoluteDifference(sum_l, target) == sum_l - target;
    assert AbsoluteDifference(sum_b, target) >= AbsoluteDifference(sum_l, target);
  }
}

method threeSumClosest(nums: seq<int>, target: int) returns (result: int)
  requires |nums| >= 3
  ensures  threeSumClosestPost(nums, target, result)
{
    var n := |nums|;
    if n < 3 { return 0; }

    var arr := new int[n];
    var i := 0;
    while i < n
        invariant 0 <= i <= n
        invariant arr.Length == n
        invariant forall idx :: 0 <= idx < i ==> arr[idx] == nums[idx]
    {
        arr[i] := nums[i];
        i := i + 1;
    }
    assert arr[..] == nums;

    // Sort array (selection sort)
    i := 0;
    while i < n
        invariant 0 <= i <= n
        invariant arr.Length == n
        invariant multiset(arr[..]) == multiset(nums)
        invariant forall a, b :: 0 <= a < i && i <= b < n ==> arr[a] <= arr[b]
        invariant forall a, b :: 0 <= a < b < i ==> arr[a] <= arr[b]
    {
        var j := i + 1;
        while j < n
            invariant i + 1 <= j <= n
            invariant arr.Length == n
            invariant multiset(arr[..]) == multiset(nums)
            invariant forall a, b :: 0 <= a < i && i <= b < n ==> arr[a] <= arr[b]
            invariant forall a, b :: 0 <= a < b < i ==> arr[a] <= arr[b]
            invariant forall b :: i + 1 <= b < j ==> arr[i] <= arr[b]
        {
            if arr[j] < arr[i] {
                ghost var oldArr := arr[..];
                var temp := arr[i];
                arr[i] := arr[j];
                arr[j] := temp;
                assert arr[..] == oldArr[i := oldArr[j]][j := oldArr[i]];
                swapPreservesMultiset(oldArr, i, j);
            }
            j := j + 1;
        }
        i := i + 1;
    }

    assert multiset(arr[..]) == multiset(nums);
    assert forall a, b :: 0 <= a < b < n ==> arr[a] <= arr[b];

    var closest := arr[0] + arr[1] + arr[2];
    ghost var ci, cj, ck := 0, 1, 2;

    i := 0;
    while i < n - 2
        invariant 0 <= i <= n - 2
        invariant arr.Length == n
        invariant multiset(arr[..]) == multiset(nums)
        invariant forall a, b :: 0 <= a < b < n ==> arr[a] <= arr[b]
        invariant 0 <= ci < cj < ck < n
        invariant closest == arr[ci] + arr[cj] + arr[ck]
        invariant forall a, b, c :: 0 <= a < b < c < n && a < i ==>
            AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
    {
        var left := i + 1;
        var right := n - 1;

        while left < right
            invariant i + 1 <= left
            invariant left - 1 <= right <= n - 1
            invariant arr.Length == n
            invariant multiset(arr[..]) == multiset(nums)
            invariant forall a, b :: 0 <= a < b < n ==> arr[a] <= arr[b]
            invariant 0 <= ci < cj < ck < n
            invariant closest == arr[ci] + arr[cj] + arr[ck]
            invariant forall a, b, c :: 0 <= a < b < c < n && a < i ==>
                AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
            invariant forall b, c :: i < b < c < n && (b < left || c > right) ==>
                AbsoluteDifference(arr[i] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
        {
            var curSum := arr[i] + arr[left] + arr[right];

            if curSum == target {
                closest := curSum;
                ci := i;
                cj := left;
                ck := right;

                assert 0 <= ci < cj < ck < |arr[..]| && arr[..][ci] + arr[..][cj] + arr[..][ck] == closest;
                assert tripleAchievableOrdered(arr[..], closest);
                multisetTripleTransfer(arr[..], nums, closest);

                assert AbsoluteDifference(closest, target) == 0;
                result := curSum;
                return;
            }

            var diffCur := if target > curSum then target - curSum else curSum - target;
            var diffClosest := if target > closest then target - closest else closest - target;

            ghost var oldClosest := closest;
            ghost var oldCi, oldCj, oldCk := ci, cj, ck;

            if diffCur < diffClosest {
                closest := curSum;
                ci := i;
                cj := left;
                ck := right;
            }

            if curSum < target {
                // All triples (i, left, c) for c <= right are no better
                twoPointerLeftStep(arr[..], i, left, right, closest, target);

                left := left + 1;
            } else {
                // curSum > target
                // All triples (i, b, right) for b >= left are no better
                twoPointerRightStep(arr[..], i, left, right, closest, target);

                right := right - 1;
            }
        }

        // After inner loop, all triples (i, b, c) with i < b < c have been covered
        // We need to show this from the inner loop invariant
        // When left >= right, the only remaining unexplored triple would be (i, left, right)
        // but left >= right means no such triple exists
        // The invariant says: all (b, c) with b < left or c > right are covered
        // When left > right, for any b, c with i < b < c < n: either b < left or c > right
        // (because if b >= left and c <= right, then b > c since left > right, contradiction with b < c)

        i := i + 1;
    }

    assert i == n - 2;

    // Any valid triple (a, b, c) has a <= n-3 < n-2 == i, so a < i
    assert forall a, b, c :: 0 <= a < b < c < n ==>
        AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target);

    // Prove achievability
    assert 0 <= ci < cj < ck < |arr[..]| && arr[..][ci] + arr[..][cj] + arr[..][ck] == closest;
    assert tripleAchievableOrdered(arr[..], closest);
    multisetTripleTransfer(arr[..], nums, closest);

    // Transfer optimality from arr to nums
    // For any triple in nums, the same triple sum is achievable in arr (by reverse permutation)
    // and we've shown optimality over arr

    result := closest;
}

