    ghost var prevClosest := closestOut;
    ghost var prevCi, prevCj, prevCk := ciOut, cjOut, ckOut;

    var diffCur := AbsoluteDifference(curSum, target);
    var diffClosest := AbsoluteDifference(closestOut, target);

    if diffCur < diffClosest {
