253→  cjOut := cjIn;
254→  ckOut := ckIn;
255→  var left := i + 1;
256→  var right := n - 1;
257→
258→  while left < right
259→      invariant i + 1 <= left
260→      invariant left - 1 <= right <= n - 1
261→      invariant 0 <= ciOut < cjOut < ckOut < n
262→      invariant closestOut == arr[ciOut] + arr[cjOut] + arr[ckOut]
263→      invariant AbsoluteDifference(closestOut, target) <= AbsoluteDifference(closestIn, target)
264→      invariant forall b, c :: i < b < c < n && (b < left || c > right) ==>
265→          AbsoluteDifference(arr[i] + arr[b] + arr[c], target) >= AbsoluteDifference(closestOut, target)
266→  {
267→    var curSum := arr[i] + arr[left] + arr[right];
268→
269→    if curSum == target {
270→      closestOut := curSum;
271→      ciOut := i;
272→      cjOut := left;
273→      ckOut := right;
274→      assert AbsoluteDifference(closestOut, target) == 0;
275→      return;
276→    }
277→
278→    ghost var prevClosest := closestOut;
279→    ghost var prevCi, prevCj, prevCk := ciOut, cjOut, ckOut;
280→
281→    var diffCur := AbsoluteDifference(curSum, target);
282→    var diffClosest := AbsoluteDifference(closestOut, target);
283→
284→    if diffCur < diffClosest {
285→      closestOut := curSum;
286→      ciOut := i;
287→      cjOut := left;
288→      ckOut := right;
289→    }
290→
291→    if curSum < target {
292→      twoPointerLeftStep(arr[..], i, left, right, closestOut, target);
293→
294→      // We need to maintain: for b < left+1 || c > right, the triple is dominated
295→      // Old invariant: b < left || c > right ==> dominated by prevClosest
296→      // New triples to cover: b == left && c <= right (except b==left, c==right which is curSum)
297→      // From twoPointerLeftStep: for c in (left, right], arr[i]+arr[left]+arr[c] >= closestOut
298→      // And the case c == left+1..right, b == left is covered
299→      // What about b == left, c == right? That's curSum, and diffCur >= diffClosest >= closestOut diff
300→
301→      left := left + 1;
302→    } else {
303→      twoPointerRightStep(arr[..], i, left, right, closestOut, target);
304→
305→      right := right - 1;
306→    }
307→  }
308→
309→  // When left >= right, for any b, c with i < b < c < n:
310→  // either b < left (covered) or c > right (covered)
311→  // because if b >= left and c <= right, then b >= left > right >= c, contradicting b < c
312→  forall b, c | i < b < c < n
313→    ensures AbsoluteDifference(arr[i] + arr[b] + arr[c], target) >= AbsoluteDifference(closestOut, target)
314→  {
315→    if b < left {
316→    } else {
317→      // b >= left >= right + 1 > right, so c > b > right, meaning c > right
318→      assert c > right;
319→    }
320→  }
321→}
322→
323→method threeSumClosest(nums: seq<int>, target: int) returns (result: int)
324→  requires |nums| >= 3
325→  ensures  threeSumClosestPost(nums, target, result)
326→{
327→    var n := |nums|;
328→    if n < 3 { return 0; }
329→
330→    var arr := new int[n];
331→    var i := 0;
332→    while i < n
333→        invariant 0 <= i <= n
334→        invariant arr.Length == n
335→        invariant forall idx :: 0 <= idx < i ==> arr[idx] == nums[idx]
336→    {
337→        arr[i] := nums[i];
338→        i := i + 1;
339→    }
340→    assert arr[..] == nums;
341→
342→    selectionSort(arr, nums);
343→
344→    var closest := arr[0] + arr[1] + arr[2];
345→    ghost var ci, cj, ck := 0, 1, 2;
346→
347→    i := 0;
348→    while i < n - 2
349→        invariant 0 <= i <= n - 2
350→        invariant arr.Length == n
351→        invariant multiset(arr[..]) == multiset(nums)
352→        invariant forall a, b :: 0 <= a < b < n ==> arr[a] <= arr[b]
353→        invariant 0 <= ci < cj < ck < n
354→        invariant closest == arr[ci] + arr[cj] + arr[ck]
355→        invariant forall a, b, c :: 0 <= a < b < c < n && a < i ==>
356→            AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
357→    {
358→        ghost var oldClosest := closest;
359→        closest, ci, cj, ck := twoPointerSearch(arr, i, target, closest, ci, cj, ck);
360→
361→        // twoPointerSearch ensures: for all b, c with i < b < c < n,
362→        //   AbsoluteDiff(arr[i]+arr[b]+arr[c], target) >= AbsoluteDiff(closest, target)
363→        // And closest is at least as good as oldClosest
364→        // Combined with the outer invariant: for a < i, all triples with first element a are dominated
365→
366→        // For the next iteration's invariant (a < i+1 = a <= i):
367→        // Case a < i: by old invariant and closest being at least as good
368→        // Case a == i: by twoPointerSearch postcondition
369→
370→        i := i + 1;
371→    }
372→
373→    assert i == n - 2;
374→
375→    // For any valid triple (a, b, c), we have a <= n-3 < n-2 = i
376→    forall a, b, c | 0 <= a < b < c < n
377→      ensures AbsoluteDifference(arr[a] + arr[b] + arr[c], target) >= AbsoluteDifference(closest, target)
378→    {
379→      assert a < n - 2;
380→      assert a < i;
381→    }
382→
383→    // Prove achievability in nums
384→    assert 0 <= ci < cj < ck < |arr[..]|;
385→    assert arr[..][ci] + arr[..][cj] + arr[..][ck] == closest;
386→    assert tripleAchievableOrdered(arr[..], closest);
387→    multisetTripleTransfer(arr[..], nums, closest);
388→
389→    // Prove optimality in nums
390→    optimalityTransfer(arr[..], nums, closest, target);
391→
392→    result := closest;
393→}
